// The DeepCopy methods on every type in this package are generated by
// controller-gen (zz_generated.deepcopy.go) and are not hand-edited. These
// tests exist not to validate the generator's logic but to lock the
// generated code's contract — every type that has +kubebuilder:object on
// it must produce an independent deep copy of every nested slice, map,
// and pointer field, so that mutating the copy never mutates the
// original. Without this coverage, a missing +k8s:deepcopy-gen tag or a
// generator regression goes silently unnoticed.

// fullyPopulatedAddonCheck returns an AddonCheck with every optional
// slice/map/pointer field non-nil so the generated DeepCopy exercises
// every branch (not just the nil-fast-path).
func fullyPopulatedAddonCheck() *AddonCheck {
	interval := metav1.Duration{Duration: 5 * time.Minute}
	timeout := metav1.Duration{Duration: 30 * time.Second}
	historyLimit := int32(10)
	lastRun := metav1.NewTime(time.Unix(1_700_000_000, 0))
	return &AddonCheck{
		TypeMeta: metav1.TypeMeta{APIVersion: GroupVersion.String(), Kind: "AddonCheck"},
		ObjectMeta: metav1.ObjectMeta{
			Name:      "sample",
			Namespace: "default",
			Labels:    map[string]string{"k": "v"},
		},
		Spec: AddonCheckSpec{
			AddonType:    "cert-manager",
			Interval:     &interval,
			Timeout:      &timeout,
			HistoryLimit: &historyLimit,
			Paused:       false,
			Policy: map[string]AddonCheckFamilyPolicy{
				"system_health": {
					Enabled:    ptr.To(true),
					Namespaces: []string{"cert-manager"},
					LabelSelector: &metav1.LabelSelector{
						MatchLabels: map[string]string{"app": "cert-manager"},
						MatchExpressions: []metav1.LabelSelectorRequirement{{
							Key:      "tier",
							Operator: metav1.LabelSelectorOpIn,
							Values:   []string{"control-plane"},
						}},
					},
					Thresholds: map[string]string{"restartWarnCount": "3"},
				},
			},
		},
		Status: AddonCheckStatus{
			Conditions: []metav1.Condition{{
				Type:               "Ready",
				Status:             metav1.ConditionTrue,
				LastTransitionTime: lastRun,
				Reason:             "RunCompleted",
				Message:            "ok",
			}},
			LastRunTime:    &lastRun,
			LastReportName: "sample-abc12",
			LastResult:     "Pass",
		},
	}
}

