// deepCopyContract asserts the three guarantees DeepCopy is supposed to
// provide: non-nil result, distinct pointer, structural equality.
//
// Zero-sized struct pointers are exempt from the distinct-pointer check
// because Go's runtime is free to alias them — `new(struct{})` may return
// the same address across calls. Structural equality is still asserted.
func deepCopyContract(t *testing.T, name string, original, copy any) {
	t.Helper()
	cv := reflect.ValueOf(copy)
	if cv.IsNil() {
		t.Fatalf("%s.DeepCopy: returned nil", name)
	}
	if cv.Type().Elem().Size() > 0 &&
		reflect.ValueOf(original).Pointer() == cv.Pointer() {
		t.Fatalf("%s.DeepCopy: returned same pointer as input", name)
	}
	if !reflect.DeepEqual(original, copy) {
		t.Fatalf("%s.DeepCopy: structural inequality between original and copy", name)
	}
}

// runtimeObjectContract asserts DeepCopyObject returns a non-nil distinct
// runtime.Object whose dynamic type matches the original. Only types with
// +kubebuilder:object:root=true implement runtime.Object.
func runtimeObjectContract(t *testing.T, name string, original runtime.Object) {
	t.Helper()
	copy := original.DeepCopyObject()
	if copy == nil {
		t.Fatalf("%s.DeepCopyObject: returned nil", name)
	}
	if reflect.TypeOf(original) != reflect.TypeOf(copy) {
		t.Fatalf("%s.DeepCopyObject: type mismatch %T vs %T", name, original, copy)
	}
}

func TestDeepCopy_AddonCheck(t *testing.T) {
	orig := fullyPopulatedAddonCheck()
	copy := orig.DeepCopy()
	deepCopyContract(t, "AddonCheck", orig, copy)

	// Independence: mutate the copy, original must stay unchanged.
	copy.Spec.Policy["system_health"].Thresholds["restartWarnCount"] = "99"
	if orig.Spec.Policy["system_health"].Thresholds["restartWarnCount"] == "99" {
		t.Fatal("AddonCheck.DeepCopy: nested map share detected (mutation leaked)")
	}

	runtimeObjectContract(t, "AddonCheck", orig)
}

func TestDeepCopy_AddonCheckList(t *testing.T) {
	orig := &AddonCheckList{
		TypeMeta: metav1.TypeMeta{APIVersion: GroupVersion.String(), Kind: "AddonCheckList"},
		Items:    []AddonCheck{*fullyPopulatedAddonCheck()},
	}
	copy := orig.DeepCopy()
	deepCopyContract(t, "AddonCheckList", orig, copy)

	copy.Items[0].Spec.AddonType = "mutated"
	if orig.Items[0].Spec.AddonType == "mutated" {
		t.Fatal("AddonCheckList.DeepCopy: Items slice share detected")
	}

	runtimeObjectContract(t, "AddonCheckList", orig)
}

