// TestDeepCopy_LeafTypesDirect covers the leaf helper types whose DeepCopy
// methods aren't reached by the resource-level tests above because their
// parents copy them by value (struct memcpy) rather than recursing into
// the generated DeepCopyInto. controller-gen still emits DeepCopy for
// every +k8s:deepcopy-gen struct, so they need direct exercise to count
// against the package coverage.
func TestDeepCopy_LeafTypesDirect(t *testing.T) {
	tests := []struct {
		name string
		do   func(t *testing.T)
	}{
		{
			name: "CheckTargetRef",
			do: func(t *testing.T) {
				orig := &CheckTargetRef{APIVersion: "v1", Kind: "Pod", Namespace: "default", Name: "x"}
				deepCopyContract(t, "CheckTargetRef", orig, orig.DeepCopy())
			},
		},
		{
			name: "ClusterHealthChildSummary",
			do: func(t *testing.T) {
				now := metav1.NewTime(time.Unix(1_700_000_000, 0))
				orig := &ClusterHealthChildSummary{
					Name: "x", Result: "Pass", Summary: "ok", ObservedAt: &now,
				}
				deepCopyContract(t, "ClusterHealthChildSummary", orig, orig.DeepCopy())
			},
		},
		{
			name: "HealthReportCheck",
			do: func(t *testing.T) {
				now := metav1.NewTime(time.Unix(1_700_000_000, 0))
				dur := metav1.Duration{Duration: 5 * time.Millisecond}
				orig := &HealthReportCheck{
					Family:     "system_health",
					Result:     HealthReportResultPass,
					TargetRef:  HealthReportTargetRef{Kind: "Pod", Name: "x"},
					Summary:    "ok",
					Details:    map[string]string{"k": "v"},
					ObservedAt: now,
					Duration:   &dur,
				}
				deepCopyContract(t, "HealthReportCheck", orig, orig.DeepCopy())
			},
		},
		{
			name: "HealthReportTargetRef",
			do: func(t *testing.T) {
				orig := &HealthReportTargetRef{APIVersion: "v1", Kind: "Pod", Name: "x"}
				deepCopyContract(t, "HealthReportTargetRef", orig, orig.DeepCopy())
			},
		},
		{
			name: "HealthReportStatus",
			do: func(t *testing.T) {
				orig := &HealthReportStatus{}
				deepCopyContract(t, "HealthReportStatus", orig, orig.DeepCopy())
			},
		},
		{
			name: "AddonCheckFamilyPolicy",
			do: func(t *testing.T) {
				orig := &AddonCheckFamilyPolicy{
					Enabled:    ptr.To(true),
					Namespaces: []string{"default"},
					LabelSelector: &metav1.LabelSelector{
						MatchLabels: map[string]string{"app": "x"},
					},
					Thresholds: map[string]string{"k": "v"},
				}
				deepCopyContract(t, "AddonCheckFamilyPolicy", orig, orig.DeepCopy())
			},
		},
		{
			name: "AddonCheckSpec",
			do: func(t *testing.T) {
				deepCopyContract(t, "AddonCheckSpec",
					&fullyPopulatedAddonCheck().Spec,
					fullyPopulatedAddonCheck().Spec.DeepCopy())
			},
		},
		{
			name: "AddonCheckStatus",
			do: func(t *testing.T) {
				deepCopyContract(t, "AddonCheckStatus",
					&fullyPopulatedAddonCheck().Status,
					fullyPopulatedAddonCheck().Status.DeepCopy())
			},
		},
		{
			name: "ClusterHealthSpec",
			do: func(t *testing.T) {
				deepCopyContract(t, "ClusterHealthSpec",
					&fullyPopulatedClusterHealth().Spec,
					fullyPopulatedClusterHealth().Spec.DeepCopy())
			},
		},
		{
			name: "ClusterHealthStatus",
			do: func(t *testing.T) {
				deepCopyContract(t, "ClusterHealthStatus",
					&fullyPopulatedClusterHealth().Status,
					fullyPopulatedClusterHealth().Status.DeepCopy())
			},
		},
		{
			name: "HealthCheckSpec",
			do: func(t *testing.T) {
				deepCopyContract(t, "HealthCheckSpec",
					&fullyPopulatedHealthCheck().Spec,
					fullyPopulatedHealthCheck().Spec.DeepCopy())
			},
		},
		{
			name: "HealthCheckStatus",
			do: func(t *testing.T) {
				deepCopyContract(t, "HealthCheckStatus",
					&fullyPopulatedHealthCheck().Status,
					fullyPopulatedHealthCheck().Status.DeepCopy())
			},
		},
		{
			name: "HealthReportSpec",
			do: func(t *testing.T) {
				deepCopyContract(t, "HealthReportSpec",
					&fullyPopulatedHealthReport().Spec,
					fullyPopulatedHealthReport().Spec.DeepCopy())
			},
		},
	}

	for _, tc := range tests {
		t.Run(tc.name, tc.do)
	}
}
